import ast, subprocess, sys

class DocstringStripper(ast.NodeTransformer):
    def _strip(self, node):
        if (node.body and isinstance(node.body[0], ast.Expr)
                and isinstance(node.body[0].value, ast.Constant)
                and isinstance(node.body[0].value.value, str)):
            node.body = node.body[1:]
            if not node.body:
                node.body = [ast.Pass()]
        self.generic_visit(node)
        return node
    visit_Module = _strip
    visit_FunctionDef = _strip
    visit_AsyncFunctionDef = _strip
    visit_ClassDef = _strip

def normalized(src):
    tree = ast.parse(src)
    tree = DocstringStripper().visit(tree)
    ast.fix_missing_locations(tree)
    return ast.dump(tree)

files = subprocess.check_output(["git","diff","--name-only","src/"]).decode().split()
bad=[]
ok=[]
for f in files:
    head = subprocess.check_output(["git","show",f"HEAD:{f}"]).decode()
    with open(f) as fh:
        cur = fh.read()
    try:
        if normalized(head) == normalized(cur):
            ok.append(f)
        else:
            bad.append(f)
    except SyntaxError as e:
        bad.append(f"{f} (SYNTAX: {e})")

print("AST-EQUIVALENT (docstring-only):", len(ok))
for f in ok: print("  OK", f)
print("NOT-EQUIVALENT:", len(bad))
for f in bad: print("  BAD", f)
sys.exit(1 if bad else 0)
